DateTime selectedStart = DateTime.now().add(const Duration(days: 1));
DateTime selectedEnd = selectedStart.add(const Duration(hours: 2));
String _money(int cents) => '${(cents / 100).toStringAsFixed(2).replaceAll('.', ',')} €';
String _date(DateTime value) => '${value.day.toString().padLeft(2, '0')}.${value.month.toString().padLeft(2, '0')}.${value.year} · ${value.hour.toString().padLeft(2, '0')}:${value.minute.toString().padLeft(2, '0')}';

class BetaScaffold extends ConsumerWidget {
  const BetaScaffold({super.key, required this.title, required this.child, this.actions});
  final String title; final Widget child; final List<Widget>? actions;
  @override Widget build(BuildContext context, WidgetRef ref) {
    final mode = ref.watch(appModeProvider);
    return Scaffold(backgroundColor: T.porcelain, appBar: AppBar(title: Text(title), actions: actions), body: Column(children: [
      if (mode == AppMode.localBeta) Container(width: double.infinity, color: T.amberSoft, padding: const EdgeInsets.all(12), child: const Text('Lokaler Beta-Modus – Buchungen werden nur auf diesem Gerät gespeichert.', textAlign: TextAlign.center, style: TextStyle(fontWeight: FontWeight.w700))),
      if (mode == AppMode.checking) const LinearProgressIndicator(),
      if (mode == AppMode.unavailable) Material(color: T.inkSoft, child: ListTile(title: const Text('API nicht erreichbar.', style: TextStyle(color: Colors.white)), trailing: TextButton(onPressed: ref.read(appModeProvider.notifier).check, child: const Text('Erneut versuchen')))),
      Expanded(child: child),
    ]));
  }
}

class ParkingDetailScreen extends ConsumerStatefulWidget { const ParkingDetailScreen({super.key, required this.id}); final String id; @override ConsumerState<ParkingDetailScreen> createState()=>_ParkingDetailState(); }
