    return SingleChildScrollView(padding:const EdgeInsets.all(24), child:Center(child:ConstrainedBox(constraints:const BoxConstraints(maxWidth:980), child:Column(crossAxisAlignment:CrossAxisAlignment.start, children:[
      Container(height:260, decoration:BoxDecoration(gradient:const LinearGradient(colors:[T.inkSoft,T.ink]),borderRadius:BorderRadius.circular(T.radius)),child:Center(child:Icon(space.covered?Icons.garage_rounded:Icons.local_parking_rounded,size:100,color:T.mint))),
      const SizedBox(height:24), Row(children:[Expanded(child:Text(space.title,style:Theme.of(context).textTheme.headlineMedium?.copyWith(fontWeight:FontWeight.w900))),IconButton(onPressed:()=>setState(()=>saved=!saved),icon:Icon(saved?Icons.bookmark:Icons.bookmark_border)),Text(saved?'Gemerkt':'Merken')]),
      Text('${space.district} · nahe ${space.landmark} · ${space.walkingMinutes} Min. zu Fuß',style:const TextStyle(color:T.muted)), const SizedBox(height:18),
      Wrap(spacing:10,children:[if(space.verified)_tag('✓ Verifiziert'),_tag('★ ${space.rating} (${space.reviewCount})'),_tag(space.accessLabel()),if(space.covered)_tag('Überdacht'),if(space.ev)_tag('E-Laden')]), const SizedBox(height:20),
      _panel(Column(crossAxisAlignment:CrossAxisAlignment.start,children:[const Text('Zeitraum wählen',style:TextStyle(fontSize:20,fontWeight:FontWeight.w800)),BookingTimeSelector(onChanged:()=>setState((){})),Text('${_money((space.hourlyPrice*100*hours).round())} gesamt',style:const TextStyle(fontWeight:FontWeight.w800))])),const SizedBox(height:16),
      _panel(Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Text(space.dimensions()),Text(space.cancellationSummary),const Text('Die genaue Adresse und Zufahrt werden nach bestätigter Buchung freigeschaltet.')])),const SizedBox(height:24),
      SizedBox(width:double.infinity,child:FilledButton(onPressed:() async { final path='/checkout/${space.id}'; final auth=ref.read(authRepositoryProvider); if(!auth.authenticated) await auth.restore(); if(!context.mounted)return; context.go(auth.authenticated?path:'/login?returnTo=${Uri.encodeComponent(path)}'); }, child:const Text('Jetzt reservieren'))),
    ]))));
  }
}

class BookingTimeSelector extends StatefulWidget {const BookingTimeSelector({super.key,required this.onChanged});final VoidCallback onChanged;@override State<BookingTimeSelector> createState()=>_TimeState();}
